function walk(dir, exts, filter) {
  let results = [];
  try {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const e of entries) {
      const full = path.join(dir, e.name);
      if (e.isDirectory()) {
        if (!['node_modules', '.next', '.git'].includes(e.name)) {
          results.push(...walk(full, exts, filter));
        }
      } else if (exts.some(ext => e.name.endsWith(ext)) && filter(full)) {
        results.push(full);
      }
    }
  } catch {}
  return results;
}

