    const data = await json(res)
    expect(data.item.hidden).toBe(true)

    expect(mockUpdate).toHaveBeenCalledWith({
      where: { id: 3 },
      data: { hidden: true },
    })
  })

  it('returns 404 for non-existent ID', async () => {
